import{_ as t,o as a,c as i,ag as h}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Quản lý Người dùng","description":"","frontmatter":{},"headers":[],"relativePath":"admin-users.md","filePath":"admin-users.md"}'),o={name:"admin-users.md"};function g(r,n,l,e,u,s){return a(),i("div",null,[...n[0]||(n[0]=[h('<h1 id="quan-ly-nguoi-dung" tabindex="-1">Quản lý Người dùng <a class="header-anchor" href="#quan-ly-nguoi-dung" aria-label="Permalink to &quot;Quản lý Người dùng&quot;">​</a></h1><blockquote><p>Quản lý tài khoản, vai trò và quyền trên nền tảng.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Khu vực Quản lý Người dùng cho phép quản trị viên xem danh sách người dùng hiện tại, thêm nhân sự mới vào hệ thống và quản lý trạng thái của họ.</p><blockquote><p>Chỉ dành cho Quản trị viên.</p></blockquote><h2 id="cau-truc-giao-dien" tabindex="-1">Cấu trúc Giao diện <a class="header-anchor" href="#cau-truc-giao-dien" aria-label="Permalink to &quot;Cấu trúc Giao diện&quot;">​</a></h2><h3 id="bang-danh-sach-nguoi-dung" tabindex="-1">Bảng Danh sách Người dùng <a class="header-anchor" href="#bang-danh-sach-nguoi-dung" aria-label="Permalink to &quot;Bảng Danh sách Người dùng&quot;">​</a></h3><p>Hiển thị danh sách tất cả tài khoản với các cột dữ liệu:</p><ul><li><strong>Công ty (Company):</strong> Tên công ty quản lý người dùng.</li><li><strong>Phòng ban (Department):</strong> Phòng ban cụ thể.</li><li><strong>Mã NV (Employee ID):</strong> Mã số nhân viên định danh.</li><li><strong>Email:</strong> Địa chỉ email liên hệ.</li><li><strong>Tên (Name):</strong> Tên hiển thị của người dùng.</li><li><strong>Trạng thái (Status):</strong> Cho biết người dùng đang Hoạt động (Khả dụng) hay đã bị Vô hiệu hóa.</li></ul><h3 id="nut-thao-tac" tabindex="-1">Nút Thao tác <a class="header-anchor" href="#nut-thao-tac" aria-label="Permalink to &quot;Nút Thao tác&quot;">​</a></h3><ul><li><strong>Bộ lọc (Filter Icon):</strong> Lọc danh sách theo Công ty, Phòng ban, trạng thái.</li><li><strong>Thêm Người dùng (+ 新增使用者):</strong> Nút chính để tạo người dùng mới.</li></ul><hr><h2 id="them-nguoi-dung-moi" tabindex="-1">Thêm Người dùng Mới <a class="header-anchor" href="#them-nguoi-dung-moi" aria-label="Permalink to &quot;Thêm Người dùng Mới&quot;">​</a></h2><p>Khi nhấp vào &quot;Thêm Người dùng&quot;, một biểu mẫu sẽ hiện ra yêu cầu các thông tin:</p><ul><li><strong>Công ty:</strong> Chọn từ danh sách thả xuống.</li><li><strong>Phòng ban:</strong> Chọn từ danh sách thả xuống sau khi đã chọn Công ty.</li><li><strong>Mã NV:</strong> Nhập mã số nhân viên.</li><li><strong>Email:</strong> Nhập địa chỉ email.</li><li><strong>Tên:</strong> Nhập họ tên đầy đủ.</li></ul><p>Sau khi điền, nhấp Xác nhận để cấp quyền truy cập nền tảng cho người dùng đó.</p>',16)])])}const m=t(o,[["render",g]]);export{d as __pageData,m as default};
